#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int **edges = (int **)malloc(m * sizeof(int *));
        for (int i = 0; i < m; i++) {
            edges[i] = (int *)malloc(2 * sizeof(int));
            scanf("%d %d", &edges[i][0], &edges[i][1]);
        }
        int max_size = 0;
        for (int i = 0; i < m; i++) {
            int size = 1;
            int *included = (int *)malloc(m * sizeof(int));
            for (int j = 0; j < m; j++) {
                included[j] = 0;
            }
            included[i] = 1;
            for (int j = i + 1; j < m; j++) {
                if (edges[i][0] == edges[j][0] || edges[i][0] == edges[j][1] || edges[i][1] == edges[j][0] || edges[i][1] == edges[j][1]) {
                    size++;
                    included[j] = 1;
                }
            }
            if (size > max_size) {
                max_size = size;
            }
            free(included);
        }
        printf("%d\n", max_size);
        for (int i = 0; i < m; i++) {
            free(edges[i]);
        }
        free(edges);
    }
    return 0;
}

