const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [n, m] = readline().split(' ').map(Number);
    const edges = [];
    for (let j = 0; j < m; j++) {
        edges.push(readline().split(' ').map(Number));
    }
    let max_size = 0;
    for (let j = 0; j < m; j++) {
        let size = 1;
        const included = new Array(m).fill(false);
        included[j] = true;
        for (let k = j + 1; k < m; k++) {
            if (edges[j][0] === edges[k][0] || edges[j][0] === edges[k][1] || edges[j][1] === edges[k][0] || edges[j][1] === edges[k][1]) {
                size++;
                included[k] = true;
            }
        }
        if (size > max_size) {
            max_size = size;
        }
    }
    console.log(max_size);
}
